-- Seed full BUM Desa COA per Kepmendesa 136/2022
BEGIN;
ON CONFLICT (kode_akun) DO UPDATE SET nama_akun=EXCLUDED.nama_akun, tipe_akun=EXCLUDED.tipe_akun, normal_balance=EXCLUDED.normal_balance, level=EXCLUDED.level, is_header=EXCLUDED.is_header, is_system_account=EXCLUDED.is_system_account, is_manual_input=EXCLUDED.is_manual_input, is_active=true, updated_at=now();

-- Wire parent_id by computing parent kode_akun from structure
UPDATE public.accounts c SET parent_id = p.id
FROM public.accounts p
WHERE p.kode_akun = CASE
  WHEN split_part(c.kode_akun,'.',4) <> '00' THEN split_part(c.kode_akun,'.',1)||'.'||split_part(c.kode_akun,'.',2)||'.'||split_part(c.kode_akun,'.',3)||'.00'
  WHEN split_part(c.kode_akun,'.',3) <> '00' THEN split_part(c.kode_akun,'.',1)||'.'||split_part(c.kode_akun,'.',2)||'.00.00'
  WHEN split_part(c.kode_akun,'.',2) <> '0'  THEN split_part(c.kode_akun,'.',1)||'.0.00.00'
  ELSE NULL
END
AND c.kode_akun <> p.kode_akun;

UPDATE public.accounts SET parent_id = NULL WHERE level = 1;

COMMIT;